#include <bits/stdc++.h>
using namespace std;
int n,s;
vector<int> a;
int main(){
	cin>>n;
	for(int i=0;i<n;i++){
		int k;
		cin>>k;
		a.push_back(k);
	}
	sort(a.begin(),a.end());
	for(int i=1;i<(n-1);i++){
		s+=a[i];
	}
	cout<<fixed<<setprecision(2)<<(s*1.00/(n-2));
	return 0;
}
